    Vec3 b(4.0f, 5.0f, 6.0f);
    float dot = a.Dot(b);
    EXPECT_FLOAT_EQ(dot, 32.0f);  // 1*4 + 2*5 + 3*6
}

TEST(Vec3Test, Length) {
